from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    try:
        import openpyxl
    except ImportError:
        return {"pass": False, "score": 0.0, "feedback": "openpyxl not available"}

    xlsx_files = list(Path(workspace_path).glob("*.xlsx"))
    roster_files = [f for f in xlsx_files if "roster" in f.name.lower() or "employee" in f.name.lower()]
    if not roster_files:
        roster_files = xlsx_files
    if not roster_files:
        return {"pass": False, "score": 0.0, "feedback": "No .xlsx file found in workspace"}

    # Expected rows: key=ID, value=list of expected values for cols A-O (0-indexed 0-14)
    # Blanks are represented as None
    expected_rows = {
        "E-1052": ["E-1052", "Teresa", "Romero", "t.romero@crestwood.edu", "Library Services", "Main", "B. Mendoza", "10/24/2013", "Non-Exempt", "Full-Time", 1369, "Active", None, None, "Remote work agreement on file — WFH Tuesdays and Thursdays."],
        "E-1064": ["E-1064", "James", "Smith", "j.smith@crestwood.edu", "Student Affairs", "Main", "B. Fernandez", "04/29/2025", "Non-Exempt", "Full-Time", 1908, "Active", None, None, None],
        "E-1158": ["E-1158", "Gabriel", "Tran", "g.tran@crestwood.edu", "Student Affairs", "Main", "E. Baker", "01/13/2008", "Non-Exempt", "Full-Time", 1961, "Active", None, None, "Flex schedule approved Mon/Wed WFH."],
    }

    def normalize(val):
        if val is None:
            return ""
        return str(val).strip()

    def date_match(actual, expected_str):
        # Accept various date formats - just check month/day/year numbers
        import re
        nums_actual = re.findall(r'\d+', str(actual))
        nums_expected = re.findall(r'\d+', expected_str)
        if len(nums_actual) >= 3 and len(nums_expected) >= 3:
            # expected is MM/DD/YYYY
            exp_month, exp_day, exp_year = nums_expected[0], nums_expected[1], nums_expected[2]
            act_flat = ''.join(nums_actual)
            return exp_month in act_flat and exp_day in act_flat and exp_year in act_flat
        return normalize(actual) == expected_str

    results = {}
    for xlsx_file in roster_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
        except Exception as e:
            continue
        for ws in wb.worksheets:
            for row in ws.iter_rows():
                if not row:
                    continue
                cell_a = normalize(row[0].value)
                if cell_a in expected_rows:
                    exp = expected_rows[cell_a]
                    row_vals = [cell.value for cell in row[:15]]
                    mismatches = []
                    for i, (actual_val, exp_val) in enumerate(zip(row_vals, exp)):
                        col_letter = chr(ord('A') + i)
                        if exp_val is None:
                            # Blank expected
                            if actual_val is not None and str(actual_val).strip() != "":
                                mismatches.append(f"Col {col_letter}: expected blank, got '{actual_val}'")
                        elif i == 7:  # Date column
                            if not date_match(actual_val, exp_val):
                                mismatches.append(f"Col {col_letter}: expected '{exp_val}', got '{actual_val}'")
                        elif i == 10:  # Numeric (ext)
                            try:
                                if abs(float(str(actual_val).strip()) - float(str(exp_val))) > 1:
                                    mismatches.append(f"Col {col_letter}: expected '{exp_val}', got '{actual_val}'")
                            except:
                                if normalize(actual_val) != str(exp_val):
                                    mismatches.append(f"Col {col_letter}: expected '{exp_val}', got '{actual_val}'")
                        elif i == 14:  # Notes - check key content loosely
                            if exp_val and normalize(actual_val).lower() != normalize(exp_val).lower():
                                # Allow partial/fuzzy match for notes
                                if not (normalize(exp_val).lower()[:20] in normalize(actual_val).lower()):
                                    mismatches.append(f"Col {col_letter}: expected '{exp_val}', got '{actual_val}'")
                        else:
                            if normalize(actual_val).lower() != normalize(exp_val).lower():
                                mismatches.append(f"Col {col_letter}: expected '{exp_val}', got '{actual_val}'")
                    results[cell_a] = mismatches

    missing = [eid for eid in expected_rows if eid not in results]
    if missing:
        return {"pass": False, "score": 0.0, "feedback": f"Could not find rows for IDs: {missing} in any .xlsx file"}

    all_mismatches = {}
    for eid, mm in results.items():
        if mm:
            all_mismatches[eid] = mm

    if not all_mismatches:
        return {"pass": True, "score": 1.0, "feedback": "All three rows (E-1052, E-1064, E-1158) have correct values in columns A-O."}
    else:
        details = '; '.join([f"{eid}: {mms}" for eid, mms in all_mismatches.items()])
        return {"pass": False, "score": 0.0, "feedback": f"Mismatches found: {details}"}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check jira_state.json"}
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}
    with open(jira_path, "r") as f:
        data = json.load(f)

    if isinstance(data, list):
        issues = data
    elif isinstance(data, dict):
        raw = data.get("issues", data)
        if isinstance(raw, dict):
            issues = list(raw.values())
        elif isinstance(raw, list):
            issues = raw
        else:
            issues = []
    else:
        issues = []

    def _summary(issue):
        if not isinstance(issue, dict):
            return ""
        fields = issue.get("fields", {}) if isinstance(issue.get("fields"), dict) else {}
        return fields.get("summary") or issue.get("summary") or issue.get("title") or issue.get("name") or ""

    def _comment_count(issue):
        if not isinstance(issue, dict):
            return 0
        fields = issue.get("fields", {}) if isinstance(issue.get("fields"), dict) else {}
        comment = fields.get("comment")
        if isinstance(comment, dict):
            inner = comment.get("comments", [])
            if isinstance(inner, list):
                return len(inner)
        if isinstance(comment, list):
            return len(comment)
        top = issue.get("comments")
        if isinstance(top, list):
            return len(top)
        if isinstance(top, dict):
            inner = top.get("comments", top)
            if isinstance(inner, list):
                return len(inner)
        return 0

    # Three issues as specified in the rubric
    targets = [
        ("Offboarding \u2014 Smith, James (E-1064)", re.compile(r'smith.*james.*e-?1064', re.IGNORECASE), 2),
        ("Offboarding \u2014 Tran, Gabriel (E-1158)", re.compile(r'tran.*gabriel.*e-?1158', re.IGNORECASE), 2),
        ("Offboarding \u2014 Romero, Teresa (E-1052)", re.compile(r'romero.*teresa.*e-?1052', re.IGNORECASE), 2),
    ]

    found = {label: None for label, _, _ in targets}
    for issue in issues:
        summary = _summary(issue)
        if not summary:
            continue
        for label, pat, _ in targets:
            if found[label] is None and pat.search(summary):
                found[label] = issue

    missing = [label for label, iss in found.items() if iss is None]
    if missing:
        return {"pass": False, "score": 0.0, "feedback": f"Could not find Jira issues: {missing}"}

    failures = []
    for label, _, expected in targets:
        actual = _comment_count(found[label])
        if actual != expected:
            failures.append(f"Issue '{label}' has {actual} comments (expected {expected})")

    if failures:
        return {"pass": False, "score": 0.0, "feedback": "; ".join(failures)}
    return {"pass": True, "score": 1.0, "feedback": "All three issues ('Offboarding \u2014 Smith, James (E-1064)', 'Offboarding \u2014 Tran, Gabriel (E-1158)', and 'Offboarding \u2014 Romero, Teresa (E-1052)') each have exactly 2 comments \u2014 no new comments were added."}

